TEMP_DIR = Path(tempfile.gettempdir()) / "kurdish_subs"
TEMP_DIR.mkdir(exist_ok=True)


def _temp(suffix: str) -> Path:
    return TEMP_DIR / f"{st.session_state.session_id}_{suffix}"


def _run(cmd: list, label: str = "") -> bool:
    """Run FFmpeg shell command; return True on success."""
    try:
        r = subprocess.run(cmd, stdout=subprocess.PIPE,
                           stderr=subprocess.PIPE, timeout=3600)
        if r.returncode != 0:
            err = r.stderr.decode("utf-8", errors="replace")[-800:]
            st.error(f"❌ FFmpeg هەڵە ({label}): {err}")
            return False
        return True
    except subprocess.TimeoutExpired:
        st.error(f"⏱️ FFmpeg timeout: {label}")
        return False
    except Exception as e:
        st.error(f"❌ هەڵە: {e}")
        return False


# ─────────────────────────────────────────────────────────────────────────────
# AUDIO EXTRACTION (with dynaudnorm for whispered dialogue)
# ─────────────────────────────────────────────────────────────────────────────
def extract_audio(video_path: Path) -> Path:
    out = _temp("audio.wav")
    ok  = _run([
        "ffmpeg", "-y", "-i", str(video_path),
        "-vn", "-af", "dynaudnorm=f=150:g=15",
        "-acodec", "pcm_s16le", "-ar", "16000", "-ac", "1",
        str(out),
    ], "extract_audio")
    if ok:
        return out
    raise RuntimeError("دەرکردنی دەنگ سەرنەکەوت.")


# ─────────────────────────────────────────────────────────────────────────────
# WHISPER TRANSCRIPTION
# ─────────────────────────────────────────────────────────────────────────────
@st.cache_resource(show_spinner="🔊 مۆدێلی Whisper بارکردن...")
def _load_whisper() -> WhisperModel:
    return WhisperModel("large-v3", device="auto", compute_type="auto")


def transcribe_audio(audio_path: Path, forced_lang: str | None) -> list:
    """
    Transcribe audio with Faster-Whisper.
    Auto-detects language if forced_lang is None.
    Returns list of {start, end, text} dicts.
    """
    model = _load_whisper()

    whisper_kwargs = {
        "vad_filter":           True,
        "vad_parameters":       {"min_silence_duration_ms": 300},
        "no_speech_threshold":  0.25,
        "word_timestamps":      True,
        "beam_size":            5,
    }

    detected_lang = forced_lang

    # Auto-detect: quick pass with beam_size=1
    if forced_lang is None:
        d_segs, d_info = model.transcribe(str(audio_path), beam_size=1)
        list(d_segs)   # consume generator
        detected_lang = d_info.language
        st.info(
            f"🌐 زمانی دۆزراوە: **{d_info.language}** "
            f"({d_info.language_probability:.1%} پشتبەستنی)"
        )

    # Main transcription
    segs, _ = model.transcribe(
        str(audio_path), language=detected_lang, **whisper_kwargs
    )

    rows = []
    for seg in segs:
        txt = seg.text.strip()
        if not txt:
            continue
        if seg.words:
            rows.append({
                "start": round(seg.words[0].start, 3),
                "end":   round(seg.words[-1].end,  3),
                "text":  txt,
            })
        else:
            # Fallback to segment timestamps (avoids silent skips)
            rows.append({
                "start": round(seg.start, 3),
                "end":   round(seg.end,   3),
                "text":  txt,
            })
    return rows


# ─────────────────────────────────────────────────────────────────────────────
# SAFE CHUNKING
# ─────────────────────────────────────────────────────────────────────────────
def build_chunks(segments: list, chunk_secs: float) -> list:
    """Group segments into time-based chunks without cutting mid-sentence."""
    if not segments:
        return []

    chunks, current, chunk_start = [], [], segments[0]["start"]

    for i, seg in enumerate(segments):
        current.append(seg)
        if (seg["end"] - chunk_start) >= chunk_secs:
            chunks.append(current)
            current = []
            if i + 1 < len(segments):
                chunk_start = segments[i + 1]["start"]

    if current:
        chunks.append(current)
    return chunks


# ─────────────────────────────────────────────────────────────────────────────
# KURDISH NUMERAL HELPER
# ─────────────────────────────────────────────────────────────────────────────
_KU = str.maketrans("0123456789", "٠١٢٣٤٥٦٧٨٩")

def _ku(n: int) -> str:
    return str(n).translate(_KU)


# ─────────────────────────────────────────────────────────────────────────────
# ASS TIMESTAMP
# ─────────────────────────────────────────────────────────────────────────────
def _ass_ts(sec: float) -> str:
    sec = max(0.0, sec)
    h   = int(sec // 3600)
    m   = int((sec % 3600) // 60)
    s   = int(sec % 60)
    cs  = int(round((sec - int(sec)) * 100))
    return f"{h}:{m:02}:{s:02}.{cs:02}"


# ─────────────────────────────────────────────────────────────────────────────
# BUILD ASS FILE
# ─────────────────────────────────────────────────────────────────────────────
def build_ass(
    translations: list,
    delay: float,
    font_size: int,
    anime_name: str,
    translator: str,
    season_ep: str,
    tech_line: str,
    credit_secs: float,
    watermark_text: str,
    wm_pos: str,
) -> str:
    header = f"""[Script Info]
ScriptType: v4.00+
PlayResX: 1920
PlayResY: 1080
ScaledBorderAndShadow: yes
YCbCr Matrix: TV.709

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Kurdish,Noto Naskh Arabic,{font_size},&H00FFFFFF,&H000000FF,&H00000000,&H64000000,-1,0,0,0,100,100,0,0,1,2.5,1.5,2,40,40,25,1
Style: Credit,Noto Naskh Arabic,30,&H00FFD700,&H000000FF,&H00000000,&H96000000,-1,0,0,0,100,100,0,0,1,1.5,1,8,30,30,20,1
Style: Watermark,Noto Naskh Arabic,22,&H80FFFFFF,&H000000FF,&H00000000,&H00000000,0,0,0,0,100,100,0,0,1,0,0,{7 if "ڕاست" in wm_pos else 8},10,10,10,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text
"""
    events = []
    credit_end = f"0:00:{credit_secs:04.2f}".replace(".", ".")

    # ── Intro credits ──────────────────────────────────────────────────────
    parts = []
    if anime_name:  parts.append(anime_name)
    if translator:  parts.append(f"وەرگێر: {translator}")
    if season_ep:   parts.append(season_ep)
    if tech_line:   parts.append(tech_line)
    if parts:
        events.append(
            f"Dialogue: 1,0:00:02.00,{_ass_ts(2.0 + credit_secs)},Credit,,0,0,0,,{r'\N'.join(parts)}"
        )

    # ── Watermark ──────────────────────────────────────────────────────────
    if watermark_text.strip():
        last_end = (translations[-1].get("end", 0) + delay) if translations else 3600.0
        events.append(
            f"Dialogue: 0,0:00:00.00,{_ass_ts(last_end)},Watermark,,0,0,0,,{watermark_text}"
        )

    # ── Main subtitles ─────────────────────────────────────────────────────
    for row in translations:
        start = row.get("start", 0.0) + delay
        end   = row.get("end",   0.0) + delay
        text  = row.get("text",  "").strip()
        if not text or start >= end:
            continue
        events.append(
            f"Dialogue: 0,{_ass_ts(start)},{_ass_ts(end)},Kurdish,,0,0,0,,{text}"
        )

    return header + "\n".join(events)


