# BURN SUBTITLES
# ─────────────────────────────────────────────────────────────────────────────
def burn_subtitles(video: Path, ass: Path, out: Path) -> bool:
    return _run([
        "ffmpeg", "-y", "-i", str(video),
        "-vf", f"ass={str(ass)}",
        "-c:v", "libx264", "-preset", "fast", "-crf", "18",
        "-c:a", "aac", "-b:a", "192k",
        "-movflags", "+faststart",
        str(out),
    ], "burn_subtitles")


